update zephyr_knowledge_base
set name = #{name}, description = #{description}, embed_model_id = #{embedModelId}, updated_at = #{updatedAt}
where id = #{id}

update zephyr_knowledge_doc
set status = #{status}
  , chunk_count = #{chunkCount}
  , error_msg = #{errorMsg}
where id = #{id}

update zephyr_knowledge_doc
set file_name = #{fileName}, content = #{content}, status = #{status},
    chunk_count = #{chunkCount}, updated_at = #{updatedAt}
where id = #{id}
